import type * as DMMF from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import {
  fieldToTsType,
  generateCreateInput,
  generateEnum,
  generateFileContent,
  generateModelInterface,
  generateUpdateInput,
  generateWhereUniqueInput,
  lowerFirst,
  mapScalarType,
} from '../template'

const makeField = (overrides: Partial<DMMF.Field>): DMMF.Field => ({
  kind: 'scalar',
  name: 'field',
  isRequired: true,
  isList: false,
  isUnique: false,
  isId: false,
  isReadOnly: false,
  type: 'String',
  hasDefaultValue: false,
  ...overrides,
})

const makeModel = (overrides: Partial<DMMF.Model> = {}): DMMF.Model => ({
  name: 'User',
  dbName: null,
  schema: null,
  fields: [
    makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
    makeField({ name: 'email', type: 'String', isUnique: true }),
    makeField({ name: 'name', type: 'String', isRequired: false }),
    makeField({ name: 'posts', kind: 'object', type: 'Post', isList: true }),
  ],
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
  ...overrides,
})

describe('mapScalarType', () => {
  test('maps known Prisma scalars to TypeScript types', () => {
    expect(mapScalarType('String')).toBe('string')
    expect(mapScalarType('Boolean')).toBe('boolean')
    expect(mapScalarType('Int')).toBe('number')
    expect(mapScalarType('Float')).toBe('number')
    expect(mapScalarType('DateTime')).toBe('string')
    expect(mapScalarType('BigInt')).toBe('bigint')
    expect(mapScalarType('Json')).toBe('unknown')
    expect(mapScalarType('Bytes')).toBe('string')
    expect(mapScalarType('Decimal')).toBe('string')
  })

  test('returns unknown for unrecognized types', () => {
    expect(mapScalarType('CustomType')).toBe('unknown')
  })
})

describe('fieldToTsType', () => {
  test('maps a required scalar field', () => {
    expect(fieldToTsType(makeField({ type: 'String', isRequired: true }))).toBe('string')
  })

  test('maps an optional scalar field', () => {
    expect(fieldToTsType(makeField({ type: 'Int', isRequired: false }))).toBe('number | null')
  })

  test('maps a list field', () => {
    expect(fieldToTsType(makeField({ type: 'String', isList: true }))).toBe('string[]')
  })

  test('maps an enum field', () => {
    expect(fieldToTsType(makeField({ kind: 'enum', type: 'Role' }))).toBe('Role')
  })

  test('maps an object field', () => {
    expect(fieldToTsType(makeField({ kind: 'object', type: 'Post' }))).toBe('Post')
  })
})

describe('generateModelInterface', () => {
  test('generates interface with scalar fields only', () => {
    const model = makeModel()
    const result = generateModelInterface(model)

    expect(result).toContain('export interface User {')
    expect(result).toContain('id?: number')
    expect(result).toContain('email: string')
    expect(result).toContain('name?: string | null')
    // Object fields should be excluded
    expect(result).not.toContain('posts')
  })
})

describe('generateCreateInput', () => {
  test('marks fields with defaults as optional', () => {
    const result = generateCreateInput(makeModel())

    expect(result).toContain('export interface UserCreateInput {')
    expect(result).toContain('id?: number')
    expect(result).toContain('email: string')
  })
})

describe('generateUpdateInput', () => {
  test('makes all fields optional', () => {
    const result = generateUpdateInput(makeModel())

    expect(result).toContain('export interface UserUpdateInput {')
    expect(result).toContain('id?: number')
    expect(result).toContain('email?: string')
    expect(result).toContain('name?: string | null')
  })
})

describe('generateWhereUniqueInput', () => {
  test('includes id and unique fields', () => {
    const result = generateWhereUniqueInput(makeModel())

    expect(result).toContain('export interface UserWhereUniqueInput {')
    expect(result).toContain('id?: number')
    expect(result).toContain('email?: string')
    expect(result).not.toContain('name')
  })

  test('returns Record<string, unknown> when no unique fields', () => {
    const model = makeModel({
      fields: [makeField({ name: 'value', type: 'String' })],
    })
    const result = generateWhereUniqueInput(model)

    expect(result).toContain('export type UserWhereUniqueInput = Record<string, unknown>')
  })
})

describe('generateEnum', () => {
  test('generates string union type', () => {
    const enumDef: DMMF.DatamodelEnum = {
      name: 'Role',
      values: [{ name: 'ADMIN', dbName: null }, { name: 'USER', dbName: null }],
    }
    const result = generateEnum(enumDef)

    expect(result).toBe("export type Role = 'ADMIN' | 'USER'")
  })
})

describe('lowerFirst', () => {
  test('lowercases the first character', () => {
    expect(lowerFirst('User')).toBe('user')
    expect(lowerFirst('PostComment')).toBe('postComment')
    expect(lowerFirst('a')).toBe('a')
  })
})

describe('generateFileContent', () => {
  test('produces complete file with all sections', () => {
    const models = [makeModel()]
    const enums: DMMF.DatamodelEnum[] = [
      { name: 'Role', values: [{ name: 'ADMIN', dbName: null }] },
    ]
    const content = generateFileContent(models, enums)

    expect(content).toContain('// This file was generated by @prisma/generator-rest-client')
    expect(content).toContain("export type Role = 'ADMIN'")
    expect(content).toContain('export interface User {')
    expect(content).toContain('export interface UserCreateInput {')
    expect(content).toContain('export interface UserUpdateInput {')
    expect(content).toContain('export interface UserWhereUniqueInput {')
    expect(content).toContain('export class PrismaRestClient {')
    expect(content).toContain('userFindMany')
    expect(content).toContain('userFindUnique')
    expect(content).toContain('userCreate')
    expect(content).toContain('userUpdate')
    expect(content).toContain('userDelete')
  })
})

