    expect(fieldToTsType(makeField({ kind: 'enum', type: 'Role' }))).toBe('Role')
  })

  test('maps an object field', () => {
    expect(fieldToTsType(makeField({ kind: 'object', type: 'Post' }))).toBe('Post')
  })
